#[pliron_op(
    name = "nvvm.neg_f16x2",
    format,
    interfaces = [NOpdsInterface<1>, NResultsInterface<1>],
)]
pub struct NegF16x2Op;

impl NegF16x2Op {
    pub fn new(op: Ptr<Operation>) -> Self {
        Self { op }
    }

    pub fn build(ctx: &mut Context, arg0: Value) -> Ptr<Operation> {
        let result_ty = IntegerType::get(ctx, 32, Signedness::Unsigned);
        Operation::new(
            ctx,
            Self::get_concrete_op_info(),
            vec![result_ty.into()],
            vec![arg0],
            vec![],
            0,
        )
    }
}

impl Verify for NegF16x2Op {
    fn verify(&self, ctx: &Context) -> Result<(), Error> {
        let op = self.get_operation().deref(ctx);
        if op.get_num_operands() != 1 || op.get_num_results() != 1 {
            return verify_err!(
                op.loc(),
                "nvvm.neg_f16x2 requires exactly 1 operands and one result"
            );
        }
        if !(0..1).all(|index| is_i32(ctx, op.get_operand(index).get_type(ctx)))
            || !is_i32(ctx, op.get_result(0).get_type(ctx))
        {
            return verify_err!(
                op.loc(),
                "nvvm.neg_f16x2 operands and result must be 32-bit integers"
            );
        }
        Ok(())
    }
}

